package handlers

import (
	"encoding/json"
	"entire-dashboard/db"
	gitreader "entire-dashboard/git"
	"log"
	"net/http"
	"path/filepath"
	"strconv"
)

type Handler struct {
	store *db.Store
}

func New(store *db.Store) *Handler {
	return &Handler{store: store}
}

func (h *Handler) GetRepos(w http.ResponseWriter, r *http.Request) {
	repos, err := h.store.GetRepos()
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}
	writeJSON(w, repos)
}

func (h *Handler) AddRepo(w http.ResponseWriter, r *http.Request) {
	var req struct {
		Path string `json:"path"`
	}
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		http.Error(w, "invalid request body", http.StatusBadRequest)
		return
	}
	if req.Path == "" {
		http.Error(w, "path is required", http.StatusBadRequest)
		return
	}

	absPath, err := filepath.Abs(req.Path)
	if err != nil {
		http.Error(w, "invalid path: "+err.Error(), http.StatusBadRequest)
		return
	}

	name := filepath.Base(absPath)
	repo, err := h.store.AddRepo(absPath, name)
	if err != nil {
		http.Error(w, "failed to add repo: "+err.Error(), http.StatusInternalServerError)
		return
	}
	writeJSON(w, repo)
}

func (h *Handler) DeleteRepo(w http.ResponseWriter, r *http.Request) {
	idStr := r.PathValue("id")
	id, err := strconv.Atoi(idStr)
	if err != nil {
		http.Error(w, "invalid id", http.StatusBadRequest)
		return
	}
	if err := h.store.DeleteRepo(id); err != nil {
		http.Error(w, "failed to delete repo: "+err.Error(), http.StatusInternalServerError)
		return
	}
	writeJSON(w, map[string]string{"status": "ok"})
}

func (h *Handler) GetDailyStats(w http.ResponseWriter, r *http.Request) {
	repoPath := r.URL.Query().Get("repo")
	stats, err := h.store.GetDailyStats(repoPath)
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}
	writeJSON(w, stats)
}

func (h *Handler) GetSessions(w http.ResponseWriter, r *http.Request) {
	repoPath := r.URL.Query().Get("repo")
	sessions, err := h.store.GetSessions(repoPath)
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}
	writeJSON(w, sessions)
}

// Sync reads from the git shadow branch and upserts into SQLite.
// If ?repo= is specified, syncs that repo only. Otherwise syncs all registered repos.
func (h *Handler) Sync(w http.ResponseWriter, r *http.Request) {
	repoPath := r.URL.Query().Get("repo")

	var repos []string
	if repoPath != "" {
		repos = append(repos, repoPath)
	} else {
		repoList, err := h.store.GetRepos()
		if err != nil {
			http.Error(w, "failed to list repos: "+err.Error(), http.StatusInternalServerError)
			return
		}
		for _, r := range repoList {
			repos = append(repos, r.Path)
		}
	}

	totalFound := 0
	totalInserted := 0

	for _, rp := range repos {
		reader := gitreader.NewReader(rp)
		sessions, err := reader.ReadAllSessions()
		if err != nil {
			log.Printf("sync error for %s: %v", rp, err)
			continue
		}

		inserted := 0
		for _, sess := range sessions {
			sess.RepoPath = rp
			if sess.SessionID == "" {
				log.Printf("skip session with empty session_id in %s", rp)
				continue
			}
			exists, err := h.store.SessionExists(sess.SessionID)
			if err != nil {
				log.Printf("check exists error: %v", err)
				continue
			}
			if exists {
				continue
			}
			if err := h.store.UpsertSession(sess); err != nil {
				log.Printf("upsert error: %v", err)
				continue
			}
			inserted++
		}
		totalFound += len(sessions)
		totalInserted += inserted
	}

	writeJSON(w, map[string]any{
		"total_found": totalFound,
		"inserted":    totalInserted,
		"message":     "sync complete",
	})
}

func writeJSON(w http.ResponseWriter, v any) {
	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(v)
}

package main

import (
	"entire-dashboard/db"
	"entire-dashboard/handlers"
	"flag"
	"log"
	"net/http"
	"os"
	"path/filepath"
)

func main() {
	repoPath := flag.String("repo", "", "Path to git repository (optional, can be added from UI)")
	port := flag.String("port", "8080", "Server port")
	flag.Parse()

	// DB stored in ~/.entire-dashboard/
	homeDir, err := os.UserHomeDir()
	if err != nil {
		log.Fatalf("get home dir: %v", err)
	}
	dataDir := filepath.Join(homeDir, ".entire-dashboard")
	if err := os.MkdirAll(dataDir, 0755); err != nil {
		log.Fatalf("create data dir: %v", err)
	}
	dbPath := filepath.Join(dataDir, "dashboard.db")

	store, err := db.New(dbPath)
	if err != nil {
		log.Fatalf("open db: %v", err)
	}
	defer store.Close()

	// If --repo is provided, register it as a repository
	if *repoPath != "" {
		absRepo, err := filepath.Abs(*repoPath)
		if err != nil {
			log.Fatalf("resolve repo path: %v", err)
		}
		name := filepath.Base(absRepo)
		if _, err := store.AddRepo(absRepo, name); err != nil {
			// Ignore duplicate error (already registered)
			log.Printf("repo registration: %v (may already exist)", err)
		}
	}

	h := handlers.New(store)

	mux := http.NewServeMux()

	// API routes
	mux.HandleFunc("GET /api/repos", h.GetRepos)
	mux.HandleFunc("POST /api/repos", h.AddRepo)
	mux.HandleFunc("DELETE /api/repos/{id}", h.DeleteRepo)
	mux.HandleFunc("GET /api/daily-stats", h.GetDailyStats)
	mux.HandleFunc("GET /api/sessions", h.GetSessions)
	mux.HandleFunc("POST /api/sync", h.Sync)

	// Serve frontend static files
	frontendDir := filepath.Join(filepath.Dir(os.Args[0]), "..", "frontend", "dist")
	if _, err := os.Stat(frontendDir); err == nil {
		mux.Handle("/", http.FileServer(http.Dir(frontendDir)))
	} else {
		// Fallback: serve from relative path during development
		devFrontend := filepath.Join(".", "..", "frontend", "dist")
		if _, err := os.Stat(devFrontend); err == nil {
			mux.Handle("/", http.FileServer(http.Dir(devFrontend)))
		}
	}

	// CORS middleware for development
	handler := corsMiddleware(mux)

	log.Printf("Starting server on :%s", *port)
	log.Fatal(http.ListenAndServe(":"+*port, handler))
}

func corsMiddleware(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		w.Header().Set("Access-Control-Allow-Origin", "*")
		w.Header().Set("Access-Control-Allow-Methods", "GET, POST, DELETE, OPTIONS")
		w.Header().Set("Access-Control-Allow-Headers", "Content-Type")
		if r.Method == "OPTIONS" {
			w.WriteHeader(http.StatusOK)
			return
		}
		next.ServeHTTP(w, r)
	})
}

package db

import (
	"database/sql"
	"entire-dashboard/models"
	"fmt"

	_ "github.com/mattn/go-sqlite3"
)

type Store struct {
	db *sql.DB
}

func New(path string) (*Store, error) {
	db, err := sql.Open("sqlite3", path+"?_journal_mode=WAL")
	if err != nil {
		return nil, fmt.Errorf("open db: %w", err)
	}
	if err := migrate(db); err != nil {
		return nil, fmt.Errorf("migrate: %w", err)
	}
	return &Store{db: db}, nil
}

func migrate(db *sql.DB) error {
	_, err := db.Exec(`
		CREATE TABLE IF NOT EXISTS repositories (
			id INTEGER PRIMARY KEY AUTOINCREMENT,
			path TEXT NOT NULL UNIQUE,
			name TEXT NOT NULL DEFAULT '',
			created_at TEXT NOT NULL DEFAULT (datetime('now'))
		);

		CREATE TABLE IF NOT EXISTS sessions (
			id INTEGER PRIMARY KEY AUTOINCREMENT,
			repo_path TEXT NOT NULL DEFAULT '',
			checkpoint_id TEXT NOT NULL,
			session_id TEXT NOT NULL UNIQUE,
			agent TEXT NOT NULL DEFAULT '',
			branch TEXT NOT NULL DEFAULT '',
			created_at TEXT NOT NULL DEFAULT '',
			prompt TEXT NOT NULL DEFAULT '',
			agent_lines INTEGER NOT NULL DEFAULT 0,
			human_added INTEGER NOT NULL DEFAULT 0,
			human_modified INTEGER NOT NULL DEFAULT 0,
			human_removed INTEGER NOT NULL DEFAULT 0,
			total_committed INTEGER NOT NULL DEFAULT 0,
			agent_percentage REAL NOT NULL DEFAULT 0,
			input_tokens INTEGER NOT NULL DEFAULT 0,
			output_tokens INTEGER NOT NULL DEFAULT 0,
			api_call_count INTEGER NOT NULL DEFAULT 0
		);
		CREATE INDEX IF NOT EXISTS idx_sessions_created_at ON sessions(created_at);
		CREATE INDEX IF NOT EXISTS idx_sessions_repo_path ON sessions(repo_path);
	`)
	return err
}

// Repository CRUD

func (s *Store) AddRepo(path, name string) (models.Repository, error) {
	res, err := s.db.Exec(`INSERT INTO repositories (path, name) VALUES (?, ?)`, path, name)
	if err != nil {
		return models.Repository{}, err
	}
	id, _ := res.LastInsertId()
	return models.Repository{ID: int(id), Path: path, Name: name}, nil
}

func (s *Store) GetRepos() ([]models.Repository, error) {
	rows, err := s.db.Query(`SELECT id, path, name, created_at FROM repositories ORDER BY created_at`)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var repos []models.Repository
	for rows.Next() {
		var r models.Repository
		if err := rows.Scan(&r.ID, &r.Path, &r.Name, &r.CreatedAt); err != nil {
			return nil, err
		}
		repos = append(repos, r)
	}
	return repos, rows.Err()
}

func (s *Store) DeleteRepo(id int) error {
	tx, err := s.db.Begin()
	if err != nil {
		return err
	}
	defer tx.Rollback()

	var path string
	if err := tx.QueryRow(`SELECT path FROM repositories WHERE id = ?`, id).Scan(&path); err != nil {
		return err
	}
	if _, err := tx.Exec(`DELETE FROM sessions WHERE repo_path = ?`, path); err != nil {
		return err
	}
	if _, err := tx.Exec(`DELETE FROM repositories WHERE id = ?`, id); err != nil {
		return err
	}
	return tx.Commit()
}

// Session CRUD

func (s *Store) UpsertSession(sess models.Session) error {
	_, err := s.db.Exec(`
		INSERT INTO sessions (
			repo_path, checkpoint_id, session_id, agent, branch, created_at, prompt,
			agent_lines, human_added, human_modified, human_removed,
			total_committed, agent_percentage,
			input_tokens, output_tokens, api_call_count
		) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
		ON CONFLICT(session_id) DO UPDATE SET
			repo_path=excluded.repo_path,
			agent=excluded.agent, branch=excluded.branch,
			created_at=excluded.created_at, prompt=excluded.prompt,
			agent_lines=excluded.agent_lines, human_added=excluded.human_added,
			human_modified=excluded.human_modified, human_removed=excluded.human_removed,
			total_committed=excluded.total_committed, agent_percentage=excluded.agent_percentage,
			input_tokens=excluded.input_tokens, output_tokens=excluded.output_tokens,
			api_call_count=excluded.api_call_count
	`,
		sess.RepoPath, sess.CheckpointID, sess.SessionID, sess.Agent, sess.Branch, sess.CreatedAt, sess.Prompt,
		sess.AgentLines, sess.HumanAdded, sess.HumanModified, sess.HumanRemoved,
		sess.TotalCommitted, sess.AgentPercentage,
		sess.InputTokens, sess.OutputTokens, sess.APICallCount,
	)
	return err
}

func (s *Store) GetDailyStats(repoPath string) ([]models.DailyStat, error) {
	rows, err := s.db.Query(`
		SELECT
			substr(created_at, 1, 10) AS date,
			SUM(agent_lines) AS agent_lines,
			SUM(human_added) AS human_lines,
			SUM(agent_lines) + SUM(human_added) AS total_lines,
			CASE WHEN SUM(agent_lines) + SUM(human_added) > 0
				THEN ROUND(CAST(SUM(agent_lines) AS REAL) / (SUM(agent_lines) + SUM(human_added)) * 100, 1)
				ELSE 0
			END AS agent_percentage,
			COUNT(*) AS session_count
		FROM sessions
		WHERE (? = '' OR repo_path = ?)
		GROUP BY substr(created_at, 1, 10)
		ORDER BY date
	`, repoPath, repoPath)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var stats []models.DailyStat
	for rows.Next() {
		var s models.DailyStat
		if err := rows.Scan(&s.Date, &s.AgentLines, &s.HumanLines, &s.TotalLines, &s.AgentPercentage, &s.SessionCount); err != nil {
			return nil, err
		}
		stats = append(stats, s)
	}
	return stats, rows.Err()
}

func (s *Store) GetSessions(repoPath string) ([]models.Session, error) {
	rows, err := s.db.Query(`
		SELECT id, repo_path, checkpoint_id, session_id, agent, branch, created_at, prompt,
			agent_lines, human_added, human_modified, human_removed,
			total_committed, agent_percentage,
			input_tokens, output_tokens, api_call_count
		FROM sessions
		WHERE (? = '' OR repo_path = ?)
		ORDER BY created_at DESC
	`, repoPath, repoPath)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var sessions []models.Session
	for rows.Next() {
		var s models.Session
		if err := rows.Scan(
			&s.ID, &s.RepoPath, &s.CheckpointID, &s.SessionID, &s.Agent, &s.Branch, &s.CreatedAt, &s.Prompt,
			&s.AgentLines, &s.HumanAdded, &s.HumanModified, &s.HumanRemoved,
			&s.TotalCommitted, &s.AgentPercentage,
			&s.InputTokens, &s.OutputTokens, &s.APICallCount,
		); err != nil {
			return nil, err
		}
		sessions = append(sessions, s)
	}
	return sessions, rows.Err()
}

func (s *Store) SessionExists(sessionID string) (bool, error) {
	var count int
	err := s.db.QueryRow("SELECT COUNT(*) FROM sessions WHERE session_id = ?", sessionID).Scan(&count)
	return count > 0, err
}

func (s *Store) Close() error {
	return s.db.Close()
}

